44	func beadConnectionFromSnapshots(snaps []BeadSnapshot, first *int, after *string, last *int, before *string) *BeadConnection {
45		// Build full edge list with stable ID-based cursors.
46		all := make([]*BeadEdge, len(snaps))
47		for i, s := range snaps {
48			all[i] = &BeadEdge{
49				Node:   beadFromSnapshot(s),
50				Cursor: encodeStableCursor(s.ID),
51			}
52		}
53	
54		// Apply window: start after `after` cursor, end before `before` cursor.
55		startIdx := 0
56		if after != nil {
57			if afterID, ok := decodeStableCursor(*after); ok {
58				for i, e := range all {
59					if e.Node.ID == afterID {
60						startIdx = i + 1
61						break
62					}
63				}
64			}
65		}
66		endIdx := len(all)
67		if before != nil {
68			if beforeID, ok := decodeStableCursor(*before); ok {
69				for i, e := range all {
70					if e.Node.ID == beforeID {
71						endIdx = i
72						break
73					}
74				}
75			}
76		}
77		if startIdx > endIdx {
78			startIdx = endIdx
79		}
80	
81		slice := all[startIdx:endIdx]
82		truncatedByFirst := false
83		truncatedByLast := false
84		if first != nil && *first >= 0 && *first < len(slice) {
85			slice = slice[:*first]
86			truncatedByFirst = true
87		}
88		if last != nil && *last >= 0 && *last < len(slice) {
89			slice = slice[len(slice)-*last:]
90			truncatedByLast = true
91		}
92	
93		pageInfo := &PageInfo{
94			HasPreviousPage: startIdx > 0 || truncatedByLast,
95			HasNextPage:     endIdx < len(all) || truncatedByFirst,
96		}
97		if len(slice) > 0 {
98			pageInfo.StartCursor = &slice[0].Cursor
99			pageInfo.EndCursor = &slice[len(slice)-1].Cursor
100		}
101	
102		return &BeadConnection{
103			Edges:      slice,
104			PageInfo:   pageInfo,
105			TotalCount: len(all),
106		}
107	}
