53	// GetBeadSnapshots implements ddxgraphql.StateProvider.
54	func (s *ServerState) GetBeadSnapshots(status, label, projectID, search string) []ddxgraphql.BeadSnapshot {
55		projects := s.GetProjects()
56		var result []ddxgraphql.BeadSnapshot
57		for _, proj := range projects {
58			if projectID != "" && proj.ID != projectID {
59				continue
60			}
61			store := bead.NewStore(filepath.Join(proj.Path, ".ddx"))
62			beads, err := store.ReadAll()
63			if err != nil {
64				continue
65			}
66			for _, b := range beads {
67				if status != "" && b.Status != status {
68					continue
69				}
70				if label != "" && !containsString(b.Labels, label) {
71					continue
72				}
73				if search != "" {
74					q := strings.ToLower(search)
75					if !strings.Contains(strings.ToLower(b.ID), q) && !strings.Contains(strings.ToLower(b.Title), q) {
76						continue
77					}
78				}
79				s.rememberBeadLocation(b.ID, proj)
80				snap := beadSnapshotFromStoreBead(proj.ID, b)
81				result = append(result, snap)
82			}
83		}
84		return result
85	}
