87	// GetBeadSnapshot implements ddxgraphql.StateProvider.
88	func (s *ServerState) GetBeadSnapshot(id string) (*ddxgraphql.BeadSnapshot, bool) {
89		if id == "" {
90			return nil, false
91		}
92	
93		if loc, ok := s.lookupBeadLocation(id); ok {
94			proj := ProjectEntry{ID: loc.ProjectID, Path: loc.ProjectPath}
95			if snap, ok := readBeadSnapshotFromProject(proj, id); ok {
96				return snap, true
97			}
98			s.forgetBeadLocation(id)
99		}
100	
101		for _, proj := range s.GetProjects() {
102			if snap, ok := readBeadSnapshotFromProject(proj, id); ok {
103				s.rememberBeadLocation(id, proj)
104				return snap, true
105			}
106		}
107		return nil, false
108	}
