110	func (s *ServerState) rememberBeadLocation(id string, proj ProjectEntry) {
111		if id == "" || proj.ID == "" || proj.Path == "" {
112			return
113		}
114		s.beadIndexMu.Lock()
115		defer s.beadIndexMu.Unlock()
116		if s.beadIndex == nil {
117			s.beadIndex = make(map[string]beadIndexEntry)
118		}
119		s.beadIndex[id] = beadIndexEntry{ProjectID: proj.ID, ProjectPath: proj.Path}
120	}
