122	func (s *ServerState) lookupBeadLocation(id string) (beadIndexEntry, bool) {
123		s.beadIndexMu.RLock()
124		defer s.beadIndexMu.RUnlock()
125		if s.beadIndex == nil {
126			return beadIndexEntry{}, false
127		}
128		loc, ok := s.beadIndex[id]
129		return loc, ok
130	}
