203	// GetWorkersGraphQL implements ddxgraphql.StateProvider.
204	// Reads worker records from disk and returns them as GraphQL Worker values.
205	// If projectID is non-empty, only workers for that project root are returned.
206	func (s *ServerState) GetWorkersGraphQL(projectID string) []*ddxgraphql.Worker {
207		if s.workingDir == "" {
208			return nil
209		}
210		workersDir := filepath.Join(s.workingDir, ".ddx", "workers")
211		entries, err := os.ReadDir(workersDir)
212		if err != nil {
213			return nil
214		}
215		var out []*ddxgraphql.Worker
216		for _, entry := range entries {
217			if !entry.IsDir() {
218				continue
219			}
220			data, err := os.ReadFile(filepath.Join(workersDir, entry.Name(), "status.json"))
221			if err != nil {
222				continue
223			}
224			var rec WorkerRecord
225			if err := json.Unmarshal(data, &rec); err != nil {
226				continue
227			}
228			if projectID != "" && rec.ProjectRoot != projectID {
229				continue
230			}
231			out = append(out, workerFromRecord(rec))
232		}
233		// Newest first.
234		sort.Slice(out, func(i, j int) bool {
235			si, sj := out[i].StartedAt, out[j].StartedAt
236			if si == nil || sj == nil {
237				return si != nil
238			}
239			ti, _ := time.Parse(time.RFC3339, *si)
240			tj, _ := time.Parse(time.RFC3339, *sj)
241			return ti.After(tj)
242		})
243		return out
244	}
