263	func (s *ServerState) GetWorkerLogGraphQL(id string) *ddxgraphql.WorkerLog {
264		if s.workingDir == "" {
265			return &ddxgraphql.WorkerLog{}
266		}
267		// Read the worker record to find the log path.
268		data, err := os.ReadFile(filepath.Join(s.workingDir, ".ddx", "workers", id, "status.json"))
269		if err != nil {
270			return &ddxgraphql.WorkerLog{}
271		}
272		var rec WorkerRecord
273		if err := json.Unmarshal(data, &rec); err != nil {
274			return &ddxgraphql.WorkerLog{}
275		}
276		stdout := ""
277		if rec.StdoutPath != "" {
278			logPath := rec.StdoutPath
279			if !filepath.IsAbs(logPath) {
280				logPath = filepath.Join(s.workingDir, logPath)
281			}
282			if raw, err := os.ReadFile(logPath); err == nil {
283				stdout = string(raw)
284			}
285		}
286		return &ddxgraphql.WorkerLog{Stdout: stdout, Stderr: ""}
287	}
