325	// workerFromRecord converts a WorkerRecord to the GraphQL Worker type.
326	func workerFromRecord(rec WorkerRecord) *ddxgraphql.Worker {
327		attempts := rec.Attempts
328		successes := rec.Successes
329		failures := rec.Failures
330		w := &ddxgraphql.Worker{
331			ID:           rec.ID,
332			Kind:         rec.Kind,
333			State:        rec.State,
334			ProjectRoot:  rec.ProjectRoot,
335			Attempts:     &attempts,
336			Successes:    &successes,
337			Failures:     &failures,
338			RecentEvents: []*ddxgraphql.WorkerRecentEvent{},
339		}
340		if rec.Status != "" {
341			w.Status = &rec.Status
342		}
343		if rec.Harness != "" {
344			w.Harness = &rec.Harness
345		}
346		if rec.Provider != "" {
347			w.Provider = &rec.Provider
348		}
349		if rec.Model != "" {
350			w.Model = &rec.Model
351		}
352		if rec.Effort != "" {
353			w.Effort = &rec.Effort
354		}
355		if rec.Once {
356			b := true
357			w.Once = &b
358		}
359		if rec.PollInterval != "" {
360			w.PollInterval = &rec.PollInterval
361		}
362		if !rec.StartedAt.IsZero() {
363			s := rec.StartedAt.UTC().Format(time.RFC3339)
364			w.StartedAt = &s
365		}
366		if !rec.FinishedAt.IsZero() {
367			s := rec.FinishedAt.UTC().Format(time.RFC3339)
368			w.FinishedAt = &s
369		}
370		if rec.Error != "" {
371			w.Error = &rec.Error
372		}
373		if rec.StdoutPath != "" {
374			w.StdoutPath = &rec.StdoutPath
375		}
376		if rec.SpecPath != "" {
377			w.SpecPath = &rec.SpecPath
378		}
379		if rec.CurrentBead != "" {
380			w.CurrentBead = &rec.CurrentBead
381		}
382		if rec.LastError != "" {
383			w.LastError = &rec.LastError
384		}
385		if rec.LastResult != nil {
386			w.LastResult = workerResultFromRecord(rec.LastResult)
387		}
388		if rec.CurrentAttempt != nil {
389			w.CurrentAttempt = currentAttemptFromRecord(rec.CurrentAttempt)
390		}
391		for _, p := range rec.RecentPhases {
392			pt := p // copy
393			w.RecentPhases = append(w.RecentPhases, &ddxgraphql.PhaseTransition{
394				Phase:    pt.Phase,
395				Ts:       pt.TS.UTC().Format(time.RFC3339),
396				PhaseSeq: pt.PhaseSeq,
397			})
398		}
399		if rec.LastAttempt != nil {
400			w.LastAttempt = lastAttemptFromRecord(rec.LastAttempt)
401		}
402		if rec.LandSummary != nil {
403			w.LandSummary = landSummaryFromRecord(rec.LandSummary)
404		}
405		return w
406	}
