484	func landSummaryFromRecord(m *CoordinatorMetrics) *ddxgraphql.CoordinatorMetrics {
485		out := &ddxgraphql.CoordinatorMetrics{
486			Landed:          int(m.Landed),
487			Preserved:       int(m.Preserved),
488			Failed:          int(m.Failed),
489			PushFailed:      int(m.PushFailed),
490			TotalDurationMs: int(m.TotalDurationMS),
491			TotalCommits:    int(m.TotalCommits),
492			PreservedRatio:  m.PreservedRatio,
493		}
494		for _, sub := range m.LastSubmissions {
