590	func agentSessionFromEntry(projectID string, e agent.SessionEntry) *ddxgraphql.AgentSession {
591		sess := &ddxgraphql.AgentSession{
592			ID:         e.ID,
593			ProjectID:  projectID,
594			Harness:    e.Harness,
595			Model:      e.Model,
596			Effort:     e.Correlation["effort"],
597			DurationMs: e.Duration,
598			StartedAt:  e.Timestamp.UTC().Format(time.RFC3339),
599		}
600	
601		// Derive status and outcome from exit code / error.
602		if e.Error != "" {
603			sess.Status = "failed"
604			outcome := "failure"
605			sess.Outcome = &outcome
606			sess.Detail = &e.Error
607		} else {
608			sess.Status = "completed"
609			outcome := "success"
610			sess.Outcome = &outcome
611		}
612	
613		// EndedAt = StartedAt + duration.
614		if e.Duration > 0 {
615			endedAt := e.Timestamp.Add(time.Duration(e.Duration) * time.Millisecond).UTC().Format(time.RFC3339)
616			sess.EndedAt = &endedAt
617		}
618	
619		if e.CostUSD > 0 {
620			sess.Cost = &e.CostUSD
621		}
622	
623		// Token breakdown.
624		if e.InputTokens > 0 || e.OutputTokens > 0 || e.TotalTokens > 0 {
625			prompt := e.InputTokens
626			completion := e.OutputTokens
627			total := e.TotalTokens
628			if total == 0 {
629				total = e.Tokens
630			}
631			sess.Tokens = &ddxgraphql.TokenUsage{
632				Prompt:     &prompt,
633				Completion: &completion,
634				Total:      &total,
635			}
636		}
637	
638		if beadID, ok := e.Correlation["bead_id"]; ok && beadID != "" {
639			sess.BeadID = &beadID
640		}
641		if e.NativeLogRef != "" {
642			sess.StdoutPath = &e.NativeLogRef
643		}
644		if e.BaseRev != "" {
645			sess.BaseRev = &e.BaseRev
646		}
647		if e.ResultRev != "" {
648			sess.ResultRev = &e.ResultRev
649		}
650		return sess
651	}
