743	func execDefinitionFromRecord(def ddxexec.Definition) *ddxgraphql.ExecutionDefinition {
744		d := &ddxgraphql.ExecutionDefinition{
745			ID:          def.ID,
746			ArtifactIds: def.ArtifactIDs,
747			Active:      def.Active,
748			CreatedAt:   def.CreatedAt.UTC().Format(time.RFC3339),
749		}
750		d.Executor = &ddxgraphql.ExecutorSpec{
751			Kind:    def.Executor.Kind,
752			Command: def.Executor.Command,
753		}
754		if def.Executor.Cwd != "" {
755			d.Executor.Cwd = &def.Executor.Cwd
756		}
757		if def.Required {
758			b := true
759			d.Required = &b
760		}
761		if def.GraphSource {
762			b := true
763			d.GraphSource = &b
764		}
765		if def.Result.Metric != nil {
766			d.Result = &ddxgraphql.ResultSpec{}
767			if def.Result.Metric.Unit != "" || def.Result.Metric.ValuePath != "" {
768				d.Result.Metric = &ddxgraphql.MetricResultSpec{
769					Unit:      &def.Result.Metric.Unit,
770					ValuePath: &def.Result.Metric.ValuePath,
771				}
772			}
773		}
774		if def.Evaluation.Comparison != "" || def.Evaluation.Thresholds.WarnMS != 0 || def.Evaluation.Thresholds.RatchetMS != 0 {
775			eval := &ddxgraphql.Evaluation{}
776			if def.Evaluation.Comparison != "" {
777				eval.Comparison = &def.Evaluation.Comparison
778			}
779			if def.Evaluation.Thresholds.WarnMS != 0 || def.Evaluation.Thresholds.RatchetMS != 0 {
780				eval.Thresholds = &ddxgraphql.Thresholds{
781					WarnMs:    &def.Evaluation.Thresholds.WarnMS,
782					RatchetMs: &def.Evaluation.Thresholds.RatchetMS,
783				}
784			}
785			d.Evaluation = eval
786		}
787		return d
788	}
