790	func execRunFromRecord(rec ddxexec.RunRecord) *ddxgraphql.ExecutionRun {
791		r := &ddxgraphql.ExecutionRun{
792			ID:           rec.RunID,
793			DefinitionID: rec.DefinitionID,
794			ArtifactIds:  rec.ArtifactIDs,
795			StartedAt:    rec.StartedAt.UTC().Format(time.RFC3339),
796			FinishedAt:   rec.FinishedAt.UTC().Format(time.RFC3339),
797			Status:       rec.Status,
798			ExitCode:     rec.ExitCode,
799		}
800		if rec.MergeBlocking {
801			b := true
802			r.MergeBlocking = &b
803		}
804		if rec.AgentSessionID != "" {
805			r.AgentSessionID = &rec.AgentSessionID
806		}
807		if rec.Result.Stdout != "" {
808			r.Stdout = &rec.Result.Stdout
809		}
810		if rec.Result.Stderr != "" {
811			r.Stderr = &rec.Result.Stderr
812		}
813		if rec.Result.Parsed {
814			b := true
815			r.Parsed = &b
816			r.Value = &rec.Result.Value
817			if rec.Result.Unit != "" {
818				r.Unit = &rec.Result.Unit
819			}
820		}
821		if rec.Result.Metric != nil {
822			m := rec.Result.Metric
823			r.Metric = &ddxgraphql.MetricObservation{
824				ArtifactID:   m.ArtifactID,
825				DefinitionID: m.DefinitionID,
826				ObservedAt:   m.ObservedAt.UTC().Format(time.RFC3339),
827				Status:       m.Status,
828				Value:        m.Value,
829			}
830			if m.Unit != "" {
831				r.Metric.Unit = &m.Unit
832			}
833			if len(m.Samples) > 0 {
834				r.Metric.Samples = m.Samples
835			}
836		}
837		if rec.Provenance.Host != "" || rec.Provenance.Actor != "" {
838			r.Provenance = &ddxgraphql.Provenance{
839				Host:  &rec.Provenance.Host,
840				Actor: &rec.Provenance.Actor,
841			}
842		}
843		return r
844	}
