1	// Package bead implements the on-disk bead tracker.
2	//
3	// Size envelope (ddx-f8a11202):
4	//
5	// Individual bead fields — description, acceptance, notes, and each event's
6	// body — are bounded by MaxFieldBytes (65,535 bytes). This matches upstream
7	// bd's Dolt TEXT column limit so DDx-authored beads can always round-trip
8	// through `bd import`. Writers exceeding the cap are truncated with a
9	// `…[truncated, N bytes]` marker at AppendEvent; callers that need to
10	// preserve the full payload (notably reviewer streams) should persist to a
11	// sidecar artifact under `.ddx/executions/<id>/` and record a path
12	// reference in the event body.
13	//
14	// On the read side, scanners use a 16MB buffer — real-world incidents have
15	// produced 1.46MB bead rows and ~7MB session-log rows when writers bypassed
16	// the cap. 16MB comfortably fits a bead with dozens of maxed-out fields and
17	// matches the scanner in the agent package.
18	package bead
19	
20	import (
21		"bufio"
22		"bytes"
23		"crypto/rand"
24		"encoding/hex"
25		"encoding/json"
26		"fmt"
27		"os"
28		"os/exec"
29		"path/filepath"
30		"sort"
31		"strconv"
32		"strings"
33		"time"
34	
35		"github.com/DocumentDrivenDX/ddx/internal/config"
36	)
37	
38	// Store manages beads via a pluggable backend.
39	type Store struct {
40		Collection string
41		Dir        string
42		File       string
43		Prefix     string
44		LockDir    string
45		LockWait   time.Duration
46		backend    Backend // nil means use built-in JSONL
47	}
48	
49	type StoreOption func(*Store)
50	
51	// WithCollection selects the logical bead collection. The default collection
52	// remains "beads", which maps to "beads.jsonl" in the JSONL backend.
53	func WithCollection(name string) StoreOption {
54		return func(s *Store) {
55			if cleaned := normalizeCollection(name); cleaned != "" {
56				s.Collection = cleaned
57			}
58		}
59	}
60	
61	// NewStore creates a store with the given directory.
62	// Defaults can be overridden via options or environment.
63	func NewStore(dir string, opts ...StoreOption) *Store {
64		if dir == "" {
65			dir = envOr("DDX_BEAD_DIR", ".ddx")
66		}
67		prefix := envOr("DDX_BEAD_PREFIX", "")
68		if prefix == "" {
69			workingDir := dir
70			if filepath.Base(dir) == ".ddx" {
71				workingDir = filepath.Dir(dir)
72			}
73			if cfg, err := config.LoadWithWorkingDir(workingDir); err == nil && cfg != nil && cfg.Bead != nil && cfg.Bead.IDPrefix != "" {
74				prefix = cfg.Bead.IDPrefix
75			}
76		}
77		if prefix == "" {
78			prefix = detectPrefix()
79		}
80		backendType := envOr("DDX_BEAD_BACKEND", BackendJSONL)
81	
82		s := &Store{
83			Collection: DefaultCollection,
84			Dir:        dir,
85			Prefix:     prefix,
86			LockWait:   parseDurationOr("DDX_BEAD_LOCK_TIMEOUT", 10*time.Second),
87		}
88		for _, opt := range opts {
89			if opt != nil {
90				opt(s)
91			}
92		}
93		s.File = filepath.Join(dir, s.Collection+".jsonl")
94		s.LockDir = filepath.Join(dir, s.Collection+".lock")
95	
96		// Set up external backend if configured
97		switch backendType {
98		case BackendBD, BackendBR:
99			if ext, err := NewExternalBackend(backendType, s.Collection); err == nil {
100				s.backend = ext
101			}
102			// Fall through to JSONL if tool not available
103		}
104	
105		return s
106	}
107	
108	// NewStoreWithBackend creates a store with an explicit backend (for testing).
109	func NewStoreWithBackend(dir string, b Backend) *Store {
110		s := NewStore(dir)
111		s.backend = b
112		return s
113	}
114	
115	// NewStoreWithCollection creates a store for a named logical collection.
116	func NewStoreWithCollection(dir, collection string) *Store {
117		return NewStore(dir, WithCollection(collection))
118	}
119	
120	// Init creates the storage directory and file.
121	func (s *Store) Init() error {
122		if s.backend != nil {
123			return s.backend.Init()
124		}
125		if err := os.MkdirAll(s.Dir, 0o755); err != nil {
126			return fmt.Errorf("bead: init dir: %w", err)
127		}
128		f, err := os.OpenFile(s.File, os.O_CREATE|os.O_WRONLY, 0o644)
129		if err != nil {
130			return fmt.Errorf("bead: init file: %w", err)
131		}
132		return f.Close()
133	}
134	
135	// GenID generates a unique bead ID with the configured prefix.
136	func (s *Store) GenID() (string, error) {
137		b := make([]byte, 4)
138		if _, err := rand.Read(b); err != nil {
139			return "", fmt.Errorf("bead: gen id: %w", err)
140		}
141		return fmt.Sprintf("%s-%s", s.Prefix, hex.EncodeToString(b)), nil
142	}
143	
144	// ReadAll loads all beads from the configured backend.
145	func (s *Store) ReadAll() ([]Bead, error) {
146		if s.backend != nil {
147			return s.backend.ReadAll()
148		}
149		beads, warnings, err := s.readAllRaw()
150		if err != nil {
151			return nil, fmt.Errorf("bead: read %s: %w", s.File, err)
152		}
153		beads = foldLatestBeads(beads)
154		for _, warning := range warnings {
155			fmt.Fprintln(os.Stderr, warning)
156		}
157		if len(warnings) > 0 && len(beads) > 0 {
158			repaired, repairErr := s.repairJSONL()
159			if repairErr != nil {
160				return beads, fmt.Errorf("bead: repair %s: %w", s.File, repairErr)
161			}
162			if repaired {
163				fmt.Fprintf(os.Stderr, "bead: repaired %s; backup written to %s.bak\n", s.File, s.File)
164			}
165		}
166		if len(beads) == 0 && len(warnings) > 0 {
167			return nil, fmt.Errorf("bead: read %s: %d malformed record(s), 0 valid", s.File, len(warnings))
168		}
169		return beads, nil
170	}
171	
172	func (s *Store) readAllRaw() ([]Bead, []string, error) {
173		data, err := os.ReadFile(s.File)
174		if os.IsNotExist(err) {
175			return nil, nil, nil
176		}
177		if err != nil {
178			return nil, nil, fmt.Errorf("read: %w", err)
179		}
180		beads, warnings, err := parseBeadJSONL(data)
181		if err != nil {
182			return nil, nil, err
183		}
184		return beads, warnings, nil
185	}
186	
187	func parseBeadJSONL(data []byte) ([]Bead, []string, error) {
188		scanner := bufio.NewScanner(bytes.NewReader(data))
189		// 16MB max line. Real-world extremes observed: 1.46MB bead rows when a
190		// reviewer stream dumped into events[].body, and bd-exported lines stacking
191		// many 65KB fields. bd's upstream per-field cap is 65,535 bytes; an
192		// individual bead with dozens of maxed-out fields fits comfortably in 16MB.
193		scanner.Buffer(make([]byte, 0, 64*1024), 16*1024*1024)
194	
195		var beads []Bead
196		var warnings []string
197		lineNo := 0
198		for scanner.Scan() {
199			lineNo++
200			line := strings.TrimSpace(scanner.Text())
201			if line == "" {
202				continue
203			}
204			b, err := unmarshalBead([]byte(line))
205			if err != nil {
206				warnings = append(warnings, fmt.Sprintf("bead: read line %d: %v", lineNo, err))
207				continue
208			}
209			beads = append(beads, b)
210		}
211		if err := scanner.Err(); err != nil {
212			return nil, nil, fmt.Errorf("scan jsonl: %w", err)
213		}
214		return beads, warnings, nil
215	}
216	
217	func (s *Store) repairJSONL() (bool, error) {
218		var repaired bool
219		err := s.WithLock(func() error {
220			beads, warnings, err := s.readAllRaw()
221			if err != nil {
222				return err
223			}
224			beads = foldLatestBeads(beads)
225			if len(warnings) == 0 || len(beads) == 0 {
226				return nil
227			}
228			backupPath := s.File + ".bak"
229			backupData, err := os.ReadFile(s.File)
230			if err != nil {
231				return fmt.Errorf("read current file: %w", err)
232			}
233			if err := writeAtomicFile(backupPath, backupData); err != nil {
234				return fmt.Errorf("write backup: %w", err)
235			}
236			if err := s.WriteAll(beads); err != nil {
237				return fmt.Errorf("write repaired file: %w", err)
238			}
239			repaired = true
240			return nil
241		})
242		return repaired, err
243	}
244	
245	func foldLatestBeads(beads []Bead) []Bead {
246		if len(beads) == 0 {
247			return nil
248		}
249	
250		latest := make(map[string]Bead, len(beads))
251		lastSeen := make(map[string]int, len(beads))
252		for i, b := range beads {
253			latest[b.ID] = b
254			lastSeen[b.ID] = i
255		}
256	
257		ids := make([]string, 0, len(latest))
258		for id := range latest {
259			ids = append(ids, id)
260		}
261		sort.Slice(ids, func(i, j int) bool {
262			if lastSeen[ids[i]] != lastSeen[ids[j]] {
263				return lastSeen[ids[i]] < lastSeen[ids[j]]
264			}
265			return ids[i] < ids[j]
266		})
267	
268		out := make([]Bead, 0, len(ids))
269		for _, id := range ids {
270			out = append(out, latest[id])
271		}
272		return out
273	}
274	
275	func (s *Store) readAllLatestRaw() ([]Bead, []string, error) {
276		beads, warnings, err := s.readAllRaw()
277		if err != nil {
278			return nil, nil, err
279		}
280		return foldLatestBeads(beads), warnings, nil
281	}
282	
283	// tmpPath returns a unique temp file path in the same directory as path.
284	// Uses pid + 4 random bytes so concurrent processes don't collide.
285	func tmpPath(path string) (string, error) {
286		b := make([]byte, 4)
287		if _, err := rand.Read(b); err != nil {
288			return "", err
289		}
290		return fmt.Sprintf("%s.tmp-%d-%s", path, os.Getpid(), hex.EncodeToString(b)), nil
291	}
292	
293	func writeAtomicFile(path string, data []byte) error {
294		tmp, err := tmpPath(path)
295		if err != nil {
296			return err
297		}
298		f, err := os.OpenFile(tmp, os.O_WRONLY|os.O_CREATE|os.O_EXCL, 0o644)
299		if err != nil {
300			return err
301		}
302		if _, err := f.Write(data); err != nil {
303			f.Close()
304			_ = os.Remove(tmp)
305			return err
306		}
307		if err := f.Sync(); err != nil {
308			f.Close()
309			_ = os.Remove(tmp)
310			return err
311		}
312		if err := f.Close(); err != nil {
313			_ = os.Remove(tmp)
314			return err
315		}
316		if err := os.Rename(tmp, path); err != nil {
317			_ = os.Remove(tmp)
318			return err
319		}
320		return nil
321	}
322	
323	func normalizeCollection(name string) string {
324		name = strings.TrimSpace(name)
325		if name == "" {
326			return DefaultCollection
327		}
328		name = strings.TrimSuffix(name, ".jsonl")
329		return name
330	}
331	
332	// WriteAll writes all beads to the configured backend, sorted by ID.
333	func (s *Store) WriteAll(beads []Bead) error {
334		sort.Slice(beads, func(i, j int) bool {
335			return beads[i].ID < beads[j].ID
336		})
337	
338		if s.backend != nil {
339			return s.backend.WriteAll(beads)
340		}
341	
342		if err := os.MkdirAll(s.Dir, 0o755); err != nil {
343			return fmt.Errorf("bead: mkdir: %w", err)
344		}
345	
346		tmp, err := tmpPath(s.File)
347		if err != nil {
348			return fmt.Errorf("bead: tmp name: %w", err)
349		}
350		f, err := os.OpenFile(tmp, os.O_WRONLY|os.O_CREATE|os.O_EXCL, 0o644)
351		if err != nil {
352			return fmt.Errorf("bead: create tmp: %w", err)
353		}
354	
355		enc := json.NewEncoder(f)
356		enc.SetEscapeHTML(false)
357		for _, b := range beads {
358			data, err := marshalBead(b)
359			if err != nil {
360				f.Close()
361				os.Remove(tmp)
362				return fmt.Errorf("bead: marshal: %w", err)
363			}
364			if _, err := f.Write(data); err != nil {
365				f.Close()
366				os.Remove(tmp)
367				return fmt.Errorf("bead: write: %w", err)
368			}
369			if _, err := f.WriteString("\n"); err != nil {
370				f.Close()
371				os.Remove(tmp)
372				return fmt.Errorf("bead: write newline: %w", err)
373			}
374		}
375	
376		if err := f.Sync(); err != nil {
377			f.Close()
378			os.Remove(tmp)
379			return fmt.Errorf("bead: sync tmp: %w", err)
380		}
381		if err := f.Close(); err != nil {
382			os.Remove(tmp)
383			return fmt.Errorf("bead: close tmp: %w", err)
384		}
385		if err := os.Rename(tmp, s.File); err != nil {
386			os.Remove(tmp)
387			return fmt.Errorf("bead: rename tmp: %w", err)
388		}
389		return nil
390	}
391	
392	// Create adds a new bead. Assigns defaults, validates, then persists.
393	func (s *Store) Create(b *Bead) error {
394		now := time.Now().UTC()
395		if b.ID == "" {
396			id, err := s.GenID()
397			if err != nil {
398				return err
399			}
400			b.ID = id
401		}
402		if b.IssueType == "" {
403			b.IssueType = DefaultType
404		}
405		if b.Status == "" {
406			b.Status = DefaultStatus
407		}
408		b.CreatedAt = now
409		b.UpdatedAt = now
410	
411		// Validate after defaults are applied so hooks see final state
412		if err := s.validateBead(b); err != nil {
413			return err
414		}
415		// Run create hook
416		if err := s.runHook("validate-bead-create", b); err != nil {
417			return err
418		}
419	
420		return s.WithLock(func() error {
421			beads, _, err := s.readAllLatestRaw()
422			if err != nil {
423				return err
424			}
425			// Reject duplicate IDs
426			for _, e := range beads {
427				if e.ID == b.ID {
428					return fmt.Errorf("bead: duplicate id: %s", b.ID)
429				}
430			}
431			// Validate deps reference existing beads
432			depIDs := b.DepIDs()
433			if len(depIDs) > 0 {
434				existing := make(map[string]bool)
435				for _, e := range beads {
436					existing[e.ID] = true
437				}
438				for _, dep := range depIDs {
439					if !existing[dep] {
440						return fmt.Errorf("bead: dependency not found: %s", dep)
441					}
442				}
443			}
444			beads = append(beads, *b)
445			return s.WriteAll(beads)
446		})
447	}
448	
449	// Get retrieves a bead by ID.
450	func (s *Store) Get(id string) (*Bead, error) {
451		beads, err := s.ReadAll()
452		if err != nil {
453			return nil, err
454		}
455		for _, b := range beads {
456			if b.ID == id {
457				return &b, nil
458			}
459		}
460		return nil, fmt.Errorf("bead: not found: %s", id)
461	}
462	
463	// Update modifies a bead by ID. The mutate function receives a pointer to modify.
464	func (s *Store) Update(id string, mutate func(*Bead)) error {
465		return s.WithLock(func() error {
466			beads, _, err := s.readAllLatestRaw()
467			if err != nil {
468				return err
469			}
470			found := false
471			for i := range beads {
472				if beads[i].ID == id {
473					mutate(&beads[i])
474					beads[i].UpdatedAt = time.Now().UTC()
475					// Core validation after mutation
476					if err := s.validateBead(&beads[i]); err != nil {
477						return err
478					}
479					// Run update hook
480					if err := s.runHook("validate-bead-update", &beads[i]); err != nil {
481						return err
482					}
483					found = true
484					break
485				}
486			}
487			if !found {
488				return fmt.Errorf("bead: not found: %s", id)
489			}
490			return s.WriteAll(beads)
491		})
492	}
