494	// HeartbeatInterval is how often a claim owner should refresh
495	// execute-loop-heartbeat-at while running. Exposed as a variable so tests
496	// can override it.
497	var HeartbeatInterval = 30 * time.Second
498	
499	// HeartbeatTTL is the maximum allowed age of execute-loop-heartbeat-at
500	// before another worker may reclaim the bead. Defaults to 3× HeartbeatInterval.
501	// Exposed as a variable so tests can override it.
502	var HeartbeatTTL = 90 * time.Second
503	
504	// Claim sets a bead to in_progress with claim metadata.
505	// Fails if the bead is already claimed (status == in_progress) with a
506	// fresh heartbeat. A bead whose execute-loop-heartbeat-at is older than
507	// HeartbeatTTL is considered stalled and will be reclaimed atomically.
508	func (s *Store) Claim(id, assignee string) error {
509		return s.ClaimWithOptions(id, assignee, "", "")
510	}
511	
512	// ClaimWithOptions sets a bead to in_progress with extended claim metadata.
513	// session and worktree are optional; machine is derived from os.Hostname().
514	// A stalled in_progress bead (heartbeat older than HeartbeatTTL) is reclaimed
515	// atomically under the store's lock.
516	func (s *Store) ClaimWithOptions(id, assignee, session, worktree string) error {
517		machine, _ := os.Hostname()
518		if envID := os.Getenv("DDX_MACHINE_ID"); envID != "" {
519			machine = envID
520		}
521		return s.WithLock(func() error {
522			beads, _, err := s.readAllLatestRaw()
523			if err != nil {
524				return err
525			}
526			for i := range beads {
527				if beads[i].ID != id {
528					continue
529				}
530				switch beads[i].Status {
531				case StatusOpen:
532					// normal claim path
533				case StatusInProgress:
534					if !heartbeatIsStale(beads[i].Extra) {
535						return fmt.Errorf("bead: cannot claim %s from status %s", id, beads[i].Status)
536					}
537					// stalled claim — reclaim atomically below
538				default:
539					return fmt.Errorf("bead: cannot claim %s from status %s", id, beads[i].Status)
540				}
541				if beads[i].Extra == nil {
542					beads[i].Extra = make(map[string]any)
543				}
544				now := time.Now().UTC()
545				beads[i].Status = StatusInProgress
546				beads[i].Owner = assignee
547				beads[i].UpdatedAt = now
548				beads[i].Extra["claimed-at"] = now.Format(time.RFC3339)
549				beads[i].Extra["claimed-pid"] = fmt.Sprintf("%d", os.Getpid())
550				beads[i].Extra["execute-loop-heartbeat-at"] = now.Format(time.RFC3339Nano)
551				if machine != "" {
552					beads[i].Extra["claimed-machine"] = machine
553				}
554				if session != "" {
555					beads[i].Extra["claimed-session"] = session
556				}
557				if worktree != "" {
558					beads[i].Extra["claimed-worktree"] = worktree
559				}
560				if err := s.validateBead(&beads[i]); err != nil {
561					return err
562				}
563				if err := s.runHook("validate-bead-update", &beads[i]); err != nil {
564					return err
565				}
566				return s.WriteAll(beads)
567			}
568			return fmt.Errorf("bead: not found: %s", id)
569		})
570	}
