572	// Heartbeat refreshes execute-loop-heartbeat-at on a claimed bead. Returns
573	// an error if the bead is no longer in_progress (e.g., reclaimed by another
574	// worker), allowing the caller to stop its heartbeat loop.
575	func (s *Store) Heartbeat(id string) error {
576		return s.WithLock(func() error {
577			beads, _, err := s.readAllLatestRaw()
578			if err != nil {
579				return err
580			}
581			for i := range beads {
582				if beads[i].ID != id {
583					continue
584				}
585				if beads[i].Status != StatusInProgress {
586					return fmt.Errorf("bead: cannot heartbeat %s from status %s", id, beads[i].Status)
587				}
588				if beads[i].Extra == nil {
589					beads[i].Extra = make(map[string]any)
590				}
591				beads[i].Extra["execute-loop-heartbeat-at"] = time.Now().UTC().Format(time.RFC3339Nano)
592				beads[i].UpdatedAt = time.Now().UTC()
593				return s.WriteAll(beads)
594			}
595			return fmt.Errorf("bead: not found: %s", id)
596		})
597	}
