599	// heartbeatIsStale returns true if the given bead's Extra map has no
600	// execute-loop-heartbeat-at or one older than HeartbeatTTL.
601	func heartbeatIsStale(extra map[string]any) bool {
602		if extra == nil {
603			return true
604		}
605		raw, ok := extra["execute-loop-heartbeat-at"]
606		if !ok {
607			return true
608		}
609		s, ok := raw.(string)
610		if !ok || s == "" {
611			return true
612		}
613		t, err := time.Parse(time.RFC3339Nano, s)
614		if err != nil {
615			// Fall back to RFC3339 for compatibility with legacy entries written
616			// before sub-second resolution. RFC3339Nano is the current canonical
617			// format used by both ClaimWithOptions and Heartbeat write sites.
618			t, err = time.Parse(time.RFC3339, s)
619			if err != nil {
620				return true
621			}
622		}
623		return time.Since(t) > HeartbeatTTL
624	}
