660	// IncrNoChangesCount increments the execute-loop no-changes counter for a bead
661	// and returns the new count. Used by the execute-bead worker to detect when a
662	// bead should be auto-closed after repeated no-change attempts.
663	func (s *Store) IncrNoChangesCount(id string) (int, error) {
664		var newCount int
665		err := s.Update(id, func(b *Bead) {
666			if b.Extra == nil {
667				b.Extra = make(map[string]any)
668			}
669			var count int
670			if v, ok := b.Extra["execute-loop-no-changes-count"]; ok {
671				switch n := v.(type) {
672				case int:
673					count = n
674				case float64:
675					count = int(n)
676				case int64:
677					count = int(n)
678				}
679			}
680			count++
681			b.Extra["execute-loop-no-changes-count"] = count
682			newCount = count
683		})
684		return newCount, err
