687	// MaxFieldBytes is the per-field hard cap on bead event bodies and adjacent
688	// writer paths. 65,535 bytes matches upstream bd's Dolt TEXT column size so
689	// DDx-authored beads always round-trip through `bd import`. Empirically
690	// validated against bd 1.0.2 on 2026-04-20: 65,535 accepts, 65,536 rejects.
691	const MaxFieldBytes = 65535
692	
693	// capFieldBytes enforces MaxFieldBytes on a single field value. Callers that
694	// need to preserve the full payload should persist it to a sidecar artifact
695	// and store a path reference in the field; this function is the defense-in-
696	// depth cap for code paths that don't. Returns the input unchanged when it
697	// fits; otherwise returns head+tail truncation with a byte-count marker.
698	func capFieldBytes(s string) string {
699		if len(s) <= MaxFieldBytes {
700			return s
701		}
702		// Reserve a marker that always fits; keep head heavy (2/3) so
703		// human-readable context is preserved for the common short-rationale case.
704		marker := fmt.Sprintf("\n…[truncated, %d bytes]\n", len(s))
705		budget := MaxFieldBytes - len(marker)
706		if budget <= 0 {
707			return s[:MaxFieldBytes]
708		}
709		head := (budget * 2) / 3
710		tail := budget - head
711		return s[:head] + marker + s[len(s)-tail:]
712	}
