714	func (s *Store) AppendEvent(id string, event BeadEvent) error {
715		if event.CreatedAt.IsZero() {
716			event.CreatedAt = time.Now().UTC()
717		}
718		// Defense in depth: cap every event body regardless of caller. The
719		// reviewer write path separately persists the full stream to an artifact
720		// and emits a <=512-byte body; this cap catches anything else.
721		event.Body = capFieldBytes(event.Body)
722		event.Summary = capFieldBytes(event.Summary)
723		return s.Update(id, func(b *Bead) {
724			if b.Extra == nil {
725				b.Extra = make(map[string]any)
726			}
727			var events []BeadEvent
728			if raw, ok := b.Extra["events"]; ok {
729				events = decodeBeadEvents(raw)
730			}
731			events = append(events, event)
732			encoded := make([]map[string]any, 0, len(events))
733			for _, e := range events {
734				encoded = append(encoded, map[string]any{
735					"kind":       e.Kind,
736					"summary":    e.Summary,
737					"body":       e.Body,
738					"actor":      e.Actor,
739					"created_at": e.CreatedAt,
740					"source":     e.Source,
741				})
742			}
743			b.Extra["events"] = encoded
744		})
745	}
