747	// Events returns the bead's evidence history in insertion order.
748	func (s *Store) Events(id string) ([]BeadEvent, error) {
749		b, err := s.Get(id)
750		if err != nil {
751			return nil, err
752		}
753		events := decodeBeadEvents(b.Extra["events"])
754		if len(events) == 0 {
755			return []BeadEvent{}, nil
756		}
757		out := make([]BeadEvent, len(events))
758		copy(out, events)
759		return out, nil
760	}
