767		}
768		out := make([]BeadEvent, 0, len(all))
769		for _, e := range all {
770			if e.Kind == kind {
771				out = append(out, e)
772			}
773		}
774		return out, nil
775	}
776	
777	func decodeBeadEvents(raw any) []BeadEvent {
778		switch v := raw.(type) {
779		case []BeadEvent:
780			out := make([]BeadEvent, len(v))
781			copy(out, v)
782			return out
783		case []any:
784			out := make([]BeadEvent, 0, len(v))
785			for _, item := range v {
786				m, ok := item.(map[string]any)
787				if !ok {
788					continue
789				}
790				out = append(out, beadEventFromMap(m))
791			}
792			return out
793		case []map[string]any:
794			out := make([]BeadEvent, 0, len(v))
795			for _, item := range v {
796				out = append(out, beadEventFromMap(item))
797			}
798			return out
799		default:
800			return nil
801		}
802	}
803	
804	func beadEventFromMap(m map[string]any) BeadEvent {
805		e := BeadEvent{}
806		if v, ok := m["kind"].(string); ok {
807			e.Kind = v
808		}
809		if v, ok := m["summary"].(string); ok {
810			e.Summary = v
811		}
812		if v, ok := m["body"].(string); ok {
813			e.Body = v
814		}
815		if v, ok := m["actor"].(string); ok {
816			e.Actor = v
817		}
818		if v, ok := m["source"].(string); ok {
819			e.Source = v
820		}
821		if v, ok := m["created_at"].(string); ok {
822			if parsed, err := time.Parse(time.RFC3339, v); err == nil {
823				e.CreatedAt = parsed
824			}
825		}
826		return e
827	}
