829	// Close sets a bead's status to closed.
830	func (s *Store) Close(id string) error {
831		return s.Update(id, func(b *Bead) {
832			b.Status = StatusClosed
833		})
834	}
835	
836	// ErrClosureGateRejected indicates a close was refused because the bead does
837	// not carry the evidence required for an automated closure: a terminal
838	// verdict event (review APPROVE with non-empty rationale, or an explicit
839	// review-skipped / manual-close marker) AND an execution-evidence marker
840	// (closing_commit_sha, session_id, or an execute-bead success event in the
841	// events history).
842	//
843	// Automated execute-loop paths (execute-bead + reviewer) always go through
844	// CloseWithEvidence. The plain Store.Close remains as the manual
845	// administration escape hatch — it bypasses the gate by design (ddx-e30e60a9
846	// acceptance §1).
847	var ErrClosureGateRejected = fmt.Errorf("closure gate: insufficient evidence")
848	
849	// ClosureGate inspects a bead and returns nil iff the close is safe. It
850	// rejects only the specific shapes that caused the 2026-04-18/20
851	// review-malfunction incidents:
852	//
853	//  1. axon-c5cc071a (silent false-closure): closed with no events AND no
854	//     closing_commit_sha. Rejected by the execution-evidence check —
855	//     closing_commit_sha must be non-empty OR at least one event must exist.
856	//  2. f7ae036f (broken APPROVE): a review event with summary=APPROVE whose
857	//     body is empty. Rejected — APPROVE with no rationale is exactly the
858	//     parse-mis-extract shape the reviewer bug produced.
859	//
860	// Beads without a review step (--no-review, no Reviewer configured, already-
861	// satisfied paths) pass the gate as long as they carry execution evidence.
862	// This keeps the surface small: the gate catches known-bad shapes, not every
863	// conceivable edge case. Additional invariants belong in future dedicated
864	// beads so the rejection reason stays auditable.
865	func ClosureGate(b *Bead) error {
866		if b == nil {
867			return fmt.Errorf("%w: nil bead", ErrClosureGateRejected)
868		}
869		hasClosingCommit := false
870		if sha, ok := b.Extra["closing_commit_sha"].(string); ok && strings.TrimSpace(sha) != "" {
871			hasClosingCommit = true
872		}
873		events := decodeBeadEvents(b.Extra["events"])
874		// Reject the axon-c5cc071a shape: no events AND no closing commit.
875		if len(events) == 0 && !hasClosingCommit {
876			return fmt.Errorf("%w: no execution evidence (empty events and no closing_commit_sha)", ErrClosureGateRejected)
877		}
878		// Reject the f7ae036f shape: an APPROVE verdict with empty rationale.
879		for _, e := range events {
880			if e.Kind == "review" && strings.EqualFold(strings.TrimSpace(e.Summary), "APPROVE") {
881				if strings.TrimSpace(e.Body) == "" {
882					return fmt.Errorf("%w: review APPROVE with empty rationale (malformed reviewer verdict)", ErrClosureGateRejected)
883				}
884			}
885		}
886		return nil
887	}
888	
889	// CloseWithEvidence sets a bead's status to closed and records agent session evidence.
890	// sessionID is the agent session that completed the work.
891	// commitSHA is the exact closing commit SHA when it is known.
892	//
893	// Enforces ClosureGate (ddx-e30e60a9): a bead cannot transition to closed
894	// via this path without a terminal verdict event plus execution evidence.
895	// Store.Close is the manual-administration escape hatch when the gate is
896	// inappropriate.
897	func (s *Store) CloseWithEvidence(id string, sessionID string, commitSHA string) error {
898		return s.Update(id, func(b *Bead) {
899			if b.Extra == nil {
900				b.Extra = make(map[string]any)
901			}
902			if sessionID != "" {
903				b.Extra["session_id"] = sessionID
904			}
905			if commitSHA != "" {
906				b.Extra["closing_commit_sha"] = commitSHA
907			}
908			if err := ClosureGate(b); err != nil {
909				// Surface via bead notes so a later operator audit can see why the
910				// close was refused; a single error path would be dropped by the
911				// Update callback signature (no error return).
912				appendClosureRejectNote(b, err)
913				return
914			}
915			b.Status = StatusClosed
916		})
917	}
918	
919	func appendClosureRejectNote(b *Bead, err error) {
920		stamp := time.Now().UTC().Format(time.RFC3339)
921		note := fmt.Sprintf("[%s] closure rejected: %v", stamp, err)
922		if b.Notes == "" {
923			b.Notes = note
924			return
925		}
926		b.Notes = b.Notes + "\n" + note
927	}
