929	// Reopen sets a bead's status back to open, clears claim fields, optionally
930	// appends notes, and records an immutable reopen event — all in one atomic
931	// lock acquisition.
932	func (s *Store) Reopen(id string, reason string, appendNotes string) error {
933		now := time.Now().UTC()
934		return s.WithLock(func() error {
935			beads, _, err := s.readAllLatestRaw()
936			if err != nil {
937				return err
938			}
939			found := false
940			for i := range beads {
941				if beads[i].ID != id {
942					continue
943				}
944				b := &beads[i]
945				b.Status = StatusOpen
946				b.Owner = ""
947				b.UpdatedAt = now
948				if b.Extra == nil {
949					b.Extra = make(map[string]any)
950				}
951				// Clear claim fields
952				delete(b.Extra, "claimed-at")
953				delete(b.Extra, "claimed-pid")
954				delete(b.Extra, "claimed-machine")
955				delete(b.Extra, "claimed-session")
956				delete(b.Extra, "claimed-worktree")
957				delete(b.Extra, "execute-loop-heartbeat-at")
958				// Append notes
959				if appendNotes != "" {
960					if b.Notes != "" {
961						b.Notes = b.Notes + "\n\n" + appendNotes
962					} else {
963						b.Notes = appendNotes
964					}
965				}
966				// Record reopen event
967				var events []BeadEvent
968				if raw, ok := b.Extra["events"]; ok {
969					events = decodeBeadEvents(raw)
970				}
971				evt := BeadEvent{
972					Kind:      "reopen",
973					CreatedAt: now,
974				}
975				if reason != "" {
976					evt.Summary = reason
977				}
978				events = append(events, evt)
979				encoded := make([]map[string]any, 0, len(events))
980				for _, e := range events {
981					encoded = append(encoded, map[string]any{
982						"kind":       e.Kind,
983						"summary":    e.Summary,
984						"body":       e.Body,
985						"actor":      e.Actor,
986						"created_at": e.CreatedAt,
987						"source":     e.Source,
988					})
989				}
990				b.Extra["events"] = encoded
991				if err := s.validateBead(b); err != nil {
992					return err
993				}
994				if err := s.runHook("validate-bead-update", b); err != nil {
995					return err
996				}
997				found = true
998				break
999			}
1000			if !found {
1001				return fmt.Errorf("bead: not found: %s", id)
1002			}
1003			return s.WriteAll(beads)
1004		})
1005	}
