1016	// List returns beads matching optional filters.
1017	// where is an optional map of key=value predicates that match against
1018	// known struct fields and Extra (unknown/workflow-specific) fields.
1019	func (s *Store) List(status, label string, where map[string]string) ([]Bead, error) {
1020		beads, err := s.ReadAll()
1021		if err != nil {
1022			return nil, err
1023		}
1024		var result []Bead
1025		for _, b := range beads {
1026			if status != "" && b.Status != status {
1027				continue
1028			}
1029			if label != "" && !containsString(b.Labels, label) {
1030				continue
1031			}
1032			if !matchesWhere(b, where) {
1033				continue
1034			}
1035			result = append(result, b)
1036		}
1037		return result, nil
1038	}
1039	
1040	// matchesWhere returns true if the bead satisfies all key=value predicates.
1041	// It checks known struct fields first, then falls back to Extra.
1042	func matchesWhere(b Bead, where map[string]string) bool {
1043		for k, v := range where {
1044			var actual string
1045			switch k {
1046			case "id":
1047				actual = b.ID
1048			case "title":
1049				actual = b.Title
1050			case "status":
1051				actual = b.Status
1052			case "issue_type":
1053				actual = b.IssueType
1054			case "owner":
1055				actual = b.Owner
1056			case "assignee":
1057				actual = b.Owner
1058			case "parent":
1059				actual = b.Parent
1060			case "description":
1061				actual = b.Description
1062			case "acceptance":
1063				actual = b.Acceptance
1064			case "notes":
1065				actual = b.Notes
1066			default:
1067				// Fall back to Extra map for unknown/workflow-specific fields
1068				if b.Extra != nil {
1069					if ev, ok := b.Extra[k]; ok {
1070						actual = fmt.Sprintf("%v", ev)
1071					}
1072				}
1073			}
1074			if actual != v {
1075				return false
1076			}
1077		}
1078		return true
1079	}
