1087	// ReadyExecution returns ready beads that are also execution-eligible and
1088	// not superseded. This is the filter HELIX uses for its build loop.
1089	func (s *Store) ReadyExecution() ([]Bead, error) {
1090		return s.readyFiltered(true)
1091	}
