1093	// ReadyExecutionBreakdown classifies dependency-ready beads by the reason
1094	// they are NOT execution-eligible: epic containers, retry cooldown,
1095	// execution-eligible=false, or superseded. It's the diagnostic the work loop
1096	// emits when the execution queue is empty but `ddx bead ready` is not.
1097	type ReadyExecutionBreakdown struct {
1098		SkippedEpics       []string
1099		SkippedOnCooldown  []string
1100		SkippedNotEligible []string
1101		SkippedSuperseded  []string
1102		NextRetryAfter     string
1103	}
1104	
1105	func (s *Store) ReadyExecutionBreakdown() (ReadyExecutionBreakdown, error) {
1106		out := ReadyExecutionBreakdown{}
1107		ready, err := s.Ready()
1108		if err != nil {
1109			return out, err
1110		}
1111		now := time.Now().UTC()
1112		var soonestRetry time.Time
1113		for _, b := range ready {
1114			if b.IssueType == "epic" {
1115				out.SkippedEpics = append(out.SkippedEpics, b.ID)
1116				continue
1117			}
1118			if retryAfterRaw, ok := b.Extra["execute-loop-retry-after"]; ok {
1119				if retryAfterStr, isStr := retryAfterRaw.(string); isStr && retryAfterStr != "" {
1120					if retryAfter, err := time.Parse(time.RFC3339, retryAfterStr); err == nil && retryAfter.After(now) {
1121						out.SkippedOnCooldown = append(out.SkippedOnCooldown, b.ID)
1122						if soonestRetry.IsZero() || retryAfter.Before(soonestRetry) {
1123							soonestRetry = retryAfter
1124						}
1125						continue
1126					}
1127				}
1128			}
1129			if eligible, ok := b.Extra["execution-eligible"]; ok {
1130				if val, isBool := eligible.(bool); isBool && !val {
1131					out.SkippedNotEligible = append(out.SkippedNotEligible, b.ID)
1132					continue
1133				}
1134			}
1135			if sup, ok := b.Extra["superseded-by"]; ok {
1136				if s, isStr := sup.(string); isStr && s != "" {
1137					out.SkippedSuperseded = append(out.SkippedSuperseded, b.ID)
1138					continue
1139				}
1140			}
1141		}
1142		if !soonestRetry.IsZero() {
1143			out.NextRetryAfter = soonestRetry.Format(time.RFC3339)
1144		}
1145		return out, nil
1146	}
