1148	func (s *Store) readyFiltered(executionOnly bool) ([]Bead, error) {
1149		beads, err := s.ReadAll()
1150		if err != nil {
1151			return nil, err
1152		}
1153		statusMap := make(map[string]string)
1154		for _, b := range beads {
1155			statusMap[b.ID] = b.Status
1156		}
1157	
1158		var ready []Bead
1159		for _, b := range beads {
1160			if b.Status != StatusOpen {
1161				// Surface stalled in_progress beads so a fresh worker can
1162				// reclaim them atomically in Claim().
1163				if executionOnly && b.Status == StatusInProgress && heartbeatIsStale(b.Extra) {
1164					// fall through to dependency check below
1165				} else {
1166					continue
1167				}
1168			}
1169			allSatisfied := true
1170			for _, depID := range b.DepIDs() {
1171				if statusMap[depID] != StatusClosed {
1172					allSatisfied = false
1173					break
1174				}
1175			}
1176			if !allSatisfied {
1177				continue
1178			}
1179			if executionOnly {
1180				// Epics are structural containers, not executable work items.
1181				if b.IssueType == "epic" {
1182					continue
1183				}
1184				// Filter by execution-eligible (default true if absent)
1185				eligible, ok := b.Extra["execution-eligible"]
1186				if ok {
1187					if val, isBool := eligible.(bool); isBool && !val {
1188						continue
1189					}
1190				}
1191				// Filter out superseded beads
1192				if sup, ok := b.Extra["superseded-by"]; ok {
1193					if s, isStr := sup.(string); isStr && s != "" {
1194						continue
1195					}
1196				}
1197				if retryAfterRaw, ok := b.Extra["execute-loop-retry-after"]; ok {
1198					if retryAfterStr, isStr := retryAfterRaw.(string); isStr && retryAfterStr != "" {
1199						if retryAfter, err := time.Parse(time.RFC3339, retryAfterStr); err == nil && retryAfter.After(time.Now().UTC()) {
1200							continue
1201						}
1202					}
1203				}
1204			}
1205			ready = append(ready, b)
1206		}
1207	
1208		sortBeadsForQueue(ready)
1209	
1210		return ready, nil
1211	}
