1213	// Blocked returns open beads with at least one unclosed dependency.
1214	func (s *Store) Blocked() ([]Bead, error) {
1215		beads, err := s.ReadAll()
1216		if err != nil {
1217			return nil, err
1218		}
1219		statusMap := make(map[string]string)
1220		for _, b := range beads {
1221			statusMap[b.ID] = b.Status
1222		}
1223	
1224		var blocked []Bead
1225		for _, b := range beads {
1226			if b.Status != StatusOpen {
1227				continue
1228			}
1229			for _, depID := range b.DepIDs() {
1230				if statusMap[depID] != StatusClosed {
1231					blocked = append(blocked, b)
1232					break
1233				}
1234			}
1235		}
1236		sortBeadsForQueue(blocked)
1237		return blocked, nil
1238	}
1239	
1240	// BlockedAll returns open beads that are currently not runnable, classified
1241	// by blocker kind. Dependency-blocked beads are emitted first (any unclosed
1242	// dep in their DAG); retry-parked beads whose execute-loop-retry-after is in
1243	// the future are emitted with blocker kind BlockerKindRetryCooldown. A bead
1244	// that is both dep-blocked and cooldown-parked is reported as dependency-
1245	// blocked, because deps are the stronger blocker.
1246	func (s *Store) BlockedAll() ([]BlockedBead, error) {
1247		beads, err := s.ReadAll()
1248		if err != nil {
1249			return nil, err
1250		}
1251		statusMap := make(map[string]string)
1252		for _, b := range beads {
1253			statusMap[b.ID] = b.Status
1254		}
1255	
1256		now := time.Now().UTC()
1257		var entries []BlockedBead
1258		for _, b := range beads {
1259			if b.Status != StatusOpen {
1260				continue
1261			}
1262	
1263			var unclosed []string
1264			for _, depID := range b.DepIDs() {
1265				if statusMap[depID] != StatusClosed {
1266					unclosed = append(unclosed, depID)
1267				}
1268			}
1269			if len(unclosed) > 0 {
1270				entries = append(entries, BlockedBead{
1271					Bead: b,
1272					Blocker: Blocker{
1273						Kind:           BlockerKindDependency,
1274						UnclosedDepIDs: unclosed,
1275					},
1276				})
1277				continue
1278			}
1279	
1280			retryAfterRaw, ok := b.Extra["execute-loop-retry-after"]
1281			if !ok {
1282				continue
1283			}
1284			retryAfterStr, isStr := retryAfterRaw.(string)
1285			if !isStr || retryAfterStr == "" {
1286				continue
1287			}
1288			retryAfter, err := time.Parse(time.RFC3339, retryAfterStr)
1289			if err != nil || !retryAfter.After(now) {
1290				continue
1291			}
1292			blocker := Blocker{
1293				Kind:           BlockerKindRetryCooldown,
1294				NextEligibleAt: retryAfter.UTC().Format(time.RFC3339),
1295			}
1296			if v, ok := b.Extra["execute-loop-last-status"]; ok {
1297				if s, ok := v.(string); ok {
1298					blocker.LastStatus = s
1299				}
1300			}
1301			if v, ok := b.Extra["execute-loop-last-detail"]; ok {
1302				if s, ok := v.(string); ok {
1303					blocker.LastDetail = s
1304				}
1305			}
1306			entries = append(entries, BlockedBead{
1307				Bead:    b,
1308				Blocker: blocker,
1309			})
1310		}
1311	
1312		sort.SliceStable(entries, func(i, j int) bool {
1313			if entries[i].Priority != entries[j].Priority {
1314				return entries[i].Priority < entries[j].Priority
1315			}
1316			if !entries[i].CreatedAt.Equal(entries[j].CreatedAt) {
1317				return entries[i].CreatedAt.Before(entries[j].CreatedAt)
1318			}
1319			return entries[i].ID < entries[j].ID
1320		})
1321		return entries, nil
1322	}
1323	
1324	func sortBeadsForQueue(beads []Bead) {
1325		sort.SliceStable(beads, func(i, j int) bool {
1326			if beads[i].Priority != beads[j].Priority {
1327				return beads[i].Priority < beads[j].Priority
1328			}
1329			if !beads[i].CreatedAt.Equal(beads[j].CreatedAt) {
1330				return beads[i].CreatedAt.Before(beads[j].CreatedAt)
1331			}
1332			return beads[i].ID < beads[j].ID
1333		})
1334	}
