1336	// Status returns aggregate counts.
1337	func (s *Store) Status() (*StatusCounts, error) {
1338		beads, err := s.ReadAll()
1339		if err != nil {
1340			return nil, err
1341		}
1342		ready, err := s.Ready()
1343		if err != nil {
1344			return nil, err
1345		}
1346		blocked, err := s.Blocked()
1347		if err != nil {
1348			return nil, err
1349		}
1350	
1351		counts := &StatusCounts{Total: len(beads), Ready: len(ready), Blocked: len(blocked)}
1352		for _, b := range beads {
1353			switch b.Status {
1354			case StatusOpen:
1355				counts.Open++
1356			case StatusClosed:
1357				counts.Closed++
1358			}
1359		}
1360		return counts, nil
1361	}
