1363	// DepAdd adds a dependency: id depends on depID.
1364	func (s *Store) DepAdd(id, depID string) error {
1365		return s.WithLock(func() error {
1366			beads, _, err := s.readAllLatestRaw()
1367			if err != nil {
1368				return err
1369			}
1370			var target *Bead
1371			depExists := false
1372			for i := range beads {
1373				if beads[i].ID == id {
1374					target = &beads[i]
1375				}
1376				if beads[i].ID == depID {
1377					depExists = true
1378				}
1379			}
1380			if target == nil {
1381				return fmt.Errorf("bead: not found: %s", id)
1382			}
1383			if !depExists {
1384				return fmt.Errorf("bead: dependency not found: %s", depID)
1385			}
1386			if id == depID {
1387				return fmt.Errorf("bead: cannot depend on self")
1388			}
1389			if target.HasDep(depID) {
1390				return nil // already exists
1391			}
1392	
1393			// Check for circular dependency
1394			depMap := make(map[string][]string)
1395			for _, b := range beads {
1396				depMap[b.ID] = b.DepIDs()
1397			}
1398			depMap[id] = append(append([]string{}, target.DepIDs()...), depID)
1399			if hasCycle(depMap, id) {
1400				return fmt.Errorf("bead: circular dependency: %s -> %s", id, depID)
1401			}
1402	
1403			target.AddDep(depID, "blocks")
1404			target.UpdatedAt = time.Now().UTC()
1405			return s.WriteAll(beads)
1406		})
1407	}
