1416	// DepTree returns a text representation of the dependency tree.
1417	func (s *Store) DepTree(rootID string) (string, error) {
1418		beads, err := s.ReadAll()
1419		if err != nil {
1420			return "", err
1421		}
1422		byID := make(map[string]*Bead)
1423		for i := range beads {
1424			byID[beads[i].ID] = &beads[i]
1425		}
1426	
1427		if rootID != "" {
1428			target, ok := byID[rootID]
1429			if !ok {
1430				return "", fmt.Errorf("bead: not found: %s", rootID)
1431			}
1432			var sb strings.Builder
1433			// Walk up: show the dependency chain (what this node depends on)
1434			depChain := s.depChainUp(byID, rootID)
1435			if len(depChain) > 0 {
1436				// Print deps as the tree root(s), with the target as their child
1437				for _, depID := range depChain {
1438					if dep, ok := byID[depID]; ok {
1439						fmt.Fprintf(&sb, "%s [%s] %s\n", dep.ID, dep.Status, dep.Title)
1440					}
1441				}
1442			}
1443			// Print the target node
1444			fmt.Fprintf(&sb, "%s [%s] %s\n", target.ID, target.Status, target.Title)
1445			// Print dependents (what depends on this node)
1446			var children []string
1447			for _, other := range sortedKeys(byID) {
1448				if byID[other].HasDep(rootID) {
1449					children = append(children, other)
1450				}
1451			}
1452			for _, child := range children {
1453				s.printTree(&sb, byID, child, "  ", true)
1454			}
1455			return sb.String(), nil
1456		}
1457	
1458		// Find roots (beads that have no dependencies themselves)
1459		var roots []string
1460		for _, b := range beads {
1461			if len(b.Dependencies) == 0 {
1462				roots = append(roots, b.ID)
1463			}
1464		}
1465		sort.Strings(roots)
1466	
1467		var sb strings.Builder
1468		for i, root := range roots {
1469			s.printTree(&sb, byID, root, "", i == len(roots)-1)
1470		}
1471		return sb.String(), nil
1472	}
1473	
1474	func (s *Store) printTree(sb *strings.Builder, byID map[string]*Bead, id, prefix string, last bool) {
1475		b, ok := byID[id]
1476		if !ok {
1477			return
1478		}
1479	
1480		connector := "├── "
1481		if last {
1482			connector = "└── "
1483		}
1484		if prefix == "" {
1485			connector = ""
1486		}
1487	
1488		fmt.Fprintf(sb, "%s%s%s [%s] %s\n", prefix, connector, b.ID, b.Status, b.Title)
1489	
1490		// Find beads that depend on this one (children in the tree)
1491		var children []string
1492		for _, other := range sortedKeys(byID) {
1493			if byID[other].HasDep(id) {
1494				children = append(children, other)
1495			}
1496		}
1497	
1498		childPrefix := prefix
1499		if prefix != "" {
1500			if last {
1501				childPrefix += "    "
1502			} else {
1503				childPrefix += "│   "
1504			}
1505		}
1506	
1507		for i, child := range children {
1508			s.printTree(sb, byID, child, childPrefix, i == len(children)-1)
1509		}
1510	}
