1512	// depChainUp returns the direct dependencies of a bead (upstream IDs).
1513	func (s *Store) depChainUp(byID map[string]*Bead, id string) []string {
1514		b, ok := byID[id]
1515		if !ok {
1516			return nil
1517		}
1518		return b.DepIDs()
1519	}
