1521	// validateBead checks core invariants that must hold for any bead (create or update).
1522	func (s *Store) validateBead(b *Bead) error {
1523		if strings.TrimSpace(b.Title) == "" {
1524			return fmt.Errorf("bead: title is required")
1525		}
1526		if b.Priority < MinPriority || b.Priority > MaxPriority {
1527			return fmt.Errorf("bead: priority must be %d-%d, got %d", MinPriority, MaxPriority, b.Priority)
1528		}
1529		if b.Status != StatusOpen && b.Status != StatusInProgress && b.Status != StatusClosed {
1530			return fmt.Errorf("bead: invalid status: %s", b.Status)
1531		}
1532		// Self-ref check
1533		for _, depID := range b.DepIDs() {
1534			if depID == b.ID && b.ID != "" {
1535				return fmt.Errorf("bead: cannot depend on self")
1536			}
1537		}
1538		return nil
1539	}
