1541	// detectPrefix derives the bead ID prefix from the repository/directory name,
1542	// following the bd convention (e.g., repo "my-project" → prefix "my-project").
1543	// Falls back to DefaultPrefix if detection fails.
1544	func detectPrefix() string {
1545		// Try git repo root name first
1546		cmd := exec.Command("git", "rev-parse", "--show-toplevel")
1547		if out, err := cmd.Output(); err == nil {
1548			root := strings.TrimSpace(string(out))
1549			if root != "" {
1550				return filepath.Base(root)
1551			}
1552		}
1553		// Fall back to current directory name
1554		if wd, err := os.Getwd(); err == nil {
1555			return filepath.Base(wd)
1556		}
1557		return DefaultPrefix
1558	}
