1560	func parseDurationOr(envKey string, fallback time.Duration) time.Duration {
1561		v := os.Getenv(envKey)
1562		if v == "" {
1563			return fallback
1564		}
1565		// Try as seconds (plain number)
1566		if secs, err := strconv.ParseFloat(v, 64); err == nil {
1567			return time.Duration(secs * float64(time.Second))
1568		}
1569		// Try as Go duration
1570		if d, err := time.ParseDuration(v); err == nil {
1571			return d
1572		}
1573		return fallback
1574	}
