1601	// hasCycle detects cycles in the dependency graph starting from startID.
1602	func hasCycle(deps map[string][]string, startID string) bool {
1603		visited := make(map[string]bool)
1604		stack := make(map[string]bool)
1605	
1606		var visit func(string) bool
1607		visit = func(id string) bool {
1608			visited[id] = true
1609			stack[id] = true
1610	
1611			for _, dep := range deps[id] {
1612				if !visited[dep] {
1613					if visit(dep) {
1614						return true
1615					}
1616				} else if stack[dep] {
1617					return true
1618				}
1619			}
1620	
1621			stack[id] = false
1622			return false
1623		}
1624	
1625		return visit(startID)
1626	}
