51	// loadServerState reads state from dir/server-state.json, initialising a fresh state
52	// if the file does not exist. nodeName is the resolved hostname/configured name.
53	func loadServerState(dir, nodeName string) *ServerState {
54		s := &ServerState{
55			SchemaVersion: stateSchemaVersion,
56			dir:           dir,
57			Node: NodeState{
58				Name:      nodeName,
59				ID:        nodeID(nodeName),
60				StartedAt: time.Now().UTC(),
61				LastSeen:  time.Now().UTC(),
62			},
63		}
64	
65		data, err := os.ReadFile(filepath.Join(dir, "server-state.json"))
66		if err != nil {
67			return s // fresh state
68		}
69		var persisted ServerState
70		if err := json.Unmarshal(data, &persisted); err != nil {
71			return s // corrupt — start fresh
72		}
73		// Preserve projects and node ID from prior run; update runtime fields.
74		s.Node.ID = persisted.Node.ID
75		s.Projects = persisted.Projects
76	
77		// Migration: canonicalize paths, resolve linked worktrees, dedupe, sweep.
78		s.migrate()
79		return s
