167	// RegisterProject adds or updates a project entry. Returns the entry.
168	// The path is canonicalized (symlinks resolved) and, if inside a linked git
169	// worktree, resolved to the primary worktree path before storage.
170	func (s *ServerState) RegisterProject(path string) ProjectEntry {
171		s.mu.Lock()
172		defer s.mu.Unlock()
173	
174		canonical := resolvedProjectPath(path)
175		if canonical == "" {
176			canonical = path
177		}
178	
179		now := time.Now().UTC()
180		id := projectID(canonical)
181		name := filepath.Base(canonical)
182		remote := resolveGitRemote(canonical)
183	
184		for i, p := range s.Projects {
185			if p.ID == id {
186				s.Projects[i].LastSeen = now
187				s.Projects[i].Path = canonical // normalise in case of symlink change
188				s.Projects[i].Name = name
189				// Clear any stale tombstone on re-registration.
190				s.Projects[i].Unreachable = false
191				s.Projects[i].TombstonedAt = nil
192				if remote != "" {
193					s.Projects[i].GitRemote = remote
194				}
195				return s.Projects[i]
196			}
197		}
198	
199		entry := ProjectEntry{
200			ID:           id,
201			Name:         name,
202			Path:         canonical,
203			GitRemote:    remote,
204			RegisteredAt: now,
205			LastSeen:     now,
206		}
207		s.Projects = append(s.Projects, entry)
208		return entry
209	}
210	
211	// SweepProjects checks each registered project's path on disk.
212	// Paths that no longer exist are marked unreachable with a tombstone timestamp.
213	// Entries tombstoned for more than 24 h are removed.
214	// Returns the post-sweep project list (all entries, including unreachable).
215	func (s *ServerState) SweepProjects() []ProjectEntry {
216		s.mu.Lock()
217		defer s.mu.Unlock()
218	
219		now := time.Now().UTC()
220		cutoff := now.Add(-24 * time.Hour)
221	
222		kept := make([]ProjectEntry, 0, len(s.Projects))
223		for _, p := range s.Projects {
224			_, err := os.Stat(p.Path)
225			if err == nil {
226				// Path exists — clear any stale tombstone.
227				p.Unreachable = false
228				p.TombstonedAt = nil
229				kept = append(kept, p)
230				continue
231			}
232			// Path doesn't exist.
233			if p.TombstonedAt != nil && p.TombstonedAt.Before(cutoff) {
234				// Tombstoned >24 h ago — drop the entry.
235				continue
236			}
237			if !p.Unreachable {
238				// First time marking unreachable.
239				p.Unreachable = true
240				p.TombstonedAt = &now
241			}
242			kept = append(kept, p)
243		}
244		s.Projects = kept
245		return append([]ProjectEntry(nil), s.Projects...)
246	}
