249	// When includeUnreachable is false (the default for API callers), entries
250	// marked as unreachable are omitted.
251	func (s *ServerState) GetProjects(includeUnreachable ...bool) []ProjectEntry {
252		s.mu.RLock()
253		defer s.mu.RUnlock()
254		showAll := len(includeUnreachable) > 0 && includeUnreachable[0]
255		out := make([]ProjectEntry, 0, len(s.Projects))
256		for _, p := range s.Projects {
257			if !showAll && p.Unreachable {
258				continue
259			}
260			out = append(out, p)
261		}
262		return out
263	}
