78	// Node is the resolver for the node(id: ID!) field (Relay lookup by global ID).
79	func (r *queryResolver) Node(ctx context.Context, id string) (Node, error) {
80		if strings.HasPrefix(id, "node-") {
81			snap := r.State.GetNodeSnapshot()
82			if snap.ID != id {
83				return nil, nil
84			}
85			return nodeInfoFromSnapshot(snap), nil
86		}
87		if strings.HasPrefix(id, "proj-") {
88			proj, ok := r.State.GetProjectSnapshotByID(id)
89			if !ok {
90				return nil, nil
91			}
92			return proj, nil
93		}
94		return nil, nil
95	}
