103	// Projects is the resolver for the projects field.
104	func (r *queryResolver) Projects(ctx context.Context, first *int, after *string, last *int, before *string, includeUnreachable *bool) (*ProjectConnection, error) {
105		showAll := includeUnreachable != nil && *includeUnreachable
106		projects := r.State.GetProjectSnapshots(showAll)
107	
108		// Build full edge list with stable ID-based cursors.
109		all := make([]*ProjectEdge, len(projects))
110		for i, p := range projects {
111			all[i] = &ProjectEdge{
112				Node:   p,
113				Cursor: encodeStableCursor(p.ID),
114			}
115		}
116	
117		// Apply window: start after `after` cursor, end before `before` cursor.
118		startIdx := 0
119		if after != nil {
120			if afterID, ok := decodeStableCursor(*after); ok {
121				for i, e := range all {
122					if e.Node.ID == afterID {
123						startIdx = i + 1
124						break
125					}
126				}
127			}
128		}
129		endIdx := len(all)
130		if before != nil {
131			if beforeID, ok := decodeStableCursor(*before); ok {
132				for i, e := range all {
133					if e.Node.ID == beforeID {
134						endIdx = i
135						break
136					}
137				}
138			}
139		}
140		if startIdx > endIdx {
141			startIdx = endIdx
142		}
143	
144		slice := all[startIdx:endIdx]
145		if first != nil && *first >= 0 && *first < len(slice) {
146			slice = slice[:*first]
147		}
148		if last != nil && *last >= 0 && *last < len(slice) {
149			slice = slice[len(slice)-*last:]
150		}
151	
152		pageInfo := &PageInfo{
153			HasPreviousPage: startIdx > 0,
154			HasNextPage:     endIdx < len(all),
155		}
156		if len(slice) > 0 {
157			pageInfo.StartCursor = &slice[0].Cursor
158			pageInfo.EndCursor = &slice[len(slice)-1].Cursor
159		}
160	
161		return &ProjectConnection{
162			Edges:      slice,
163			PageInfo:   pageInfo,
164			TotalCount: len(all),
165		}, nil
166	}
