259	// gqlPost sends a GraphQL request via HTTP POST and returns the parsed body.
260	// It fails the test immediately on HTTP errors or top-level GraphQL errors.
261	func gqlPost(t *testing.T, h http.Handler, query string) map[string]json.RawMessage {
262		t.Helper()
263		rawBody, _ := json.Marshal(map[string]string{"query": query})
264		req := httptest.NewRequest(http.MethodPost, "/graphql", bytes.NewReader(rawBody))
265		req.Header.Set("Content-Type", "application/json")
266		w := httptest.NewRecorder()
267		h.ServeHTTP(w, req)
268		if w.Code != http.StatusOK {
269			t.Fatalf("expected 200, got %d: %s", w.Code, w.Body.String())
270		}
271		var resp map[string]json.RawMessage
272		if err := json.Unmarshal(w.Body.Bytes(), &resp); err != nil {
273			t.Fatalf("invalid JSON: %v\nbody: %s", err, w.Body.String())
274		}
275		if errs, ok := resp["errors"]; ok {
276			t.Fatalf("GraphQL errors: %s", errs)
277		}
278		return resp
279	}
